    val cols = n.toInt
    val dp = Array.fill(rows, cols, 2)(Long.MaxValue)
    dp(0)(0)(0) = (0 + 1) * (0 + 1) // initial entry cost at (0, 0)

    val heap = mutable.PriorityQueue.empty[(Long, Int, Int, Int)](
