    val rows = m.toInt
    val cols = n.toInt
    val pq = mutable.PriorityQueue.empty[(Long, Int, Int, Int)](Ordering.by(-_._1))
    val visited = mutable.Map[(Int, Int, Int), Long]()

    val startCost = (0 + 1) * (0 + 1)
    pq.enqueue((startCost, 0, 0, 1))
    visited((0, 0, 1)) = startCost

    val directions = Array((1, 0), (0, 1))

    while (pq.nonEmpty) {
        val (currentCost, i, j, step) = pq.dequeue()
        if (i == rows - 1 && j == cols - 1) {
            return currentCost
        }
        if (visited.getOrElse((i, j, step), Long.MaxValue) < currentCost) {
            continue
        }

        if (step % 2 == 1) {
            // Odd step: move right or down
            for ((di, dj) <- directions) {
                val ni = i + di
                val nj = j + dj
                if (ni < rows && nj < cols) {
                    val enterCost = (ni + 1) * (nj + 1)
                    val newCost = currentCost + enterCost
                    val newStep = step + 1
                    val key = (ni, nj, newStep)
                    if (!visited.contains(key) || newCost < visited(key)) {
                        visited(key) = newCost
                        pq.enqueue((newCost, ni, nj, newStep))
                    }
                }
            }
        } else {
            // Even step: wait
            val waitCostHere = waitCost(i)(j)
            val newCost = currentCost + waitCostHere
            val newStep = step + 1
            val key = (i, j, newStep)
            if (!visited.contains(key) || newCost < visited(key)) {
                visited(key) = newCost
                pq.enqueue((newCost, i, j, newStep))
